                    <td className="p-5 text-center">{renderCellValue(feature.mars)}</td>
                    <td className="p-5 text-center bg-white/[0.02]">{renderCellValue(feature.krypton)}</td>
                    <td className="p-5 text-center">{renderCellValue(feature.galaxy)}</td>
                  </tr>
