    { name: 'Intelligence décisionnelle', access: '❌', terra: '❌', mars: '❌', krypton: 'Option', galaxy: '✅' },
    { name: 'Support prioritaire', access: 'Standard', terra: 'Standard', mars: 'Prioritaire', krypton: 'Premium', galaxy: 'VIP' },
    { name: 'Maintenance (après 6 mois)', access: '10 %', terra: '10 %', mars: '10 %', krypton: '10 %', galaxy: '10 %' },
  ];

  const interpretations = [
    { name: 'ACCESS', desc: 'Fondation digitale professionnelle.' },
    { name: 'TERRA', desc: 'Première activation IA.' },
    { name: 'MARS', desc: 'Automatisation structurée.' },
    { name: 'KRYPTON', desc: 'Infrastructure intelligente d’entreprise.' },
    { name: 'GALAXY', desc: 'Système IA stratégique avancé.' }
  ];

  const { activeCardId } = useCosmic();
  const [cardRects, setCardRects] = useState<Record<string, DOMRect | undefined>>({});
  const gridRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const updateRects = () => {
      if (!gridRef.current) return;
      const newRects: Record<string, DOMRect> = {};
      const gridRect = gridRef.current.getBoundingClientRect();

      for (const plan of plans) {
        const el = gridRef.current.querySelector(`[data-card-id="${plan.id}"]`);
        if (el) {
          const rect = el.getBoundingClientRect();
          newRects[plan.id] = new DOMRect(
            rect.left - gridRect.left,
            rect.top - gridRect.top,
            rect.width,
            rect.height
          );
        }
      }
      setCardRects(newRects);
    };

    updateRects();
    window.addEventListener('resize', updateRects);

    const observer = new MutationObserver(updateRects);
    if(gridRef.current) {
        observer.observe(gridRef.current, { childList: true, subtree: true, attributes: true, characterData: true });
    }

    return () => {
      window.removeEventListener('resize', updateRects);
      observer.disconnect();
    };
  }, [plans]);

  const activeRect = activeCardId ? cardRects[activeCardId] : null;

  const handleCtaClick = (planId: string) => {
    if (planId === 'ACCESS') {
      onNavigate(Page.ACCESS_OFFER);
    } else {
      onOpenFiko(planId);
    }
  };

  const renderCellValue = (value: string) => {
    if (value === '✅') return <CheckCircle2 className="mx-auto text-emerald-500" size={18} />;
    if (value === '❌') return <XCircle className="mx-auto text-red-500/40" size={18} />;
    return <span className="text-xs font-bold text-slate-300">{value}</span>;
  };

  return (
    <div className="relative bg-[#0B0B0F] overflow-hidden min-h-screen pb-40">
      <div className="absolute top-0 left-0 w-[1200px] h-[1200px] bg-[#E10600]/5 blur-[250px] rounded-full -translate-y-1/2 -translate-x-1/3 pointer-events-none"></div>

      <div className="max-w-[1800px] mx-auto px-6 pt-40 pb-20 relative z-10">

        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.7 }} className="text-center mb-24 space-y-6">
          <div className="inline-flex items-center gap-3 px-6 py-2 border border-[#E10600] bg-[#E10600]/5 text-[#E10600] text-[10px] font-black uppercase tracking-[0.5em]">
             SYSTÈME PLANÉTAIRE KRYPTON
          </div>
          <h1 className="text-6xl lg:text-[100px] font-black tracking-tighter uppercase leading-[0.85] text-white">
            CHOISISSEZ VOTRE <br/><span className="text-[#E10600] italic">PORTE D'ACCÈS.</span>
          </h1>
          <p className="text-slate-400 max-w-3xl mx-auto font-medium text-xl uppercase tracking-[0.3em] leading-relaxed italic">
            ✨ CHAQUE PORTE CACHE UN TRÉSOR. Survolez pour activer le vortex.
          </p>
        </motion.div>

        {/* Pricing Grid with reduced height h-[520px] */}
        <div ref={gridRef} className="grid grid-cols-1 lg:grid-cols-5 gap-6 relative">
          <AnimatePresence>
            {activeRect && (
              <motion.div
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1.05 }}
                exit={{ opacity: 0, scale: 0.8 }}
                transition={{ duration: 0.4, ease: 'circOut' }}
                className="absolute pointer-events-none rounded-sm"
                style={{
                  left: activeRect.x,
                  top: activeRect.y,
                  width: activeRect.width,
                  height: activeRect.height,
                  boxShadow: `0 0 80px 20px ${plans.find(p => p.id === activeCardId)?.color || '#a855f7'}`,
                  backgroundColor: `${plans.find(p => p.id === activeCardId)?.color || '#a855f7'}20`,
                }}
              />
            )}
          </AnimatePresence>

          {plans.map((plan: any, i) => (
            <motion.div
              key={plan.id}
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1, duration: 0.5 }}
              className="h-[520px] z-10"
              data-card-id={plan.id}
            >
              <GalacticCard
                  id={plan.id}
                  title={plan.name}
                  story={plan.story}
                  price={plan.price}
                  subtitle={plan.subtitle}
                  features={plan.included}
                  cta={plan.cta}
                  color={plan.color}
                  onClick={() => handleCtaClick(plan.id)}
              />
            </motion.div>
          ))}
        </div>

        {/* COMPARISON SECTION */}
        <div className="mt-40 pt-32 border-t border-white/5">
          <div className="text-center mb-24">
            <h2 className="text-5xl lg:text-7xl font-black tracking-tighter uppercase text-white">
              Comparez les <span className="text-[#E10600] italic">solutions</span>
            </h2>
            <p className="mt-6 text-xl text-slate-500 font-medium uppercase tracking-[0.3em]">
              Choisissez le niveau de performance adapté à votre ambition.
            </p>
          </div>

          <div className="overflow-x-auto custom-scrollbar border border-white/10 rounded-sm">
            <table className="w-full min-w-[1200px]">
              <thead>
                <tr className="bg-white/[0.02]">
                  <th className="p-6 w-1/4 text-left text-sm font-black uppercase tracking-widest">Fonctionnalités</th>
                  <th className="p-6 text-center text-sm font-black uppercase tracking-widest text-purple-400">ACCESS</th>
                  <th className="p-6 text-center text-sm font-black uppercase tracking-widest text-emerald-400">TERRA</th>
                  <th className="p-6 text-center text-sm font-black uppercase tracking-widest text-red-500">MARS</th>
                  <th className="p-6 text-center text-sm font-black uppercase tracking-widest text-blue-400">KRYPTON</th>
                  <th className="p-6 text-center text-sm font-black uppercase tracking-widest text-amber-400 relative">
                    GALAXY
                    <span className="absolute top-2 right-2 text-[7px] font-black bg-amber-400 text-black px-2 py-0.5 rounded-full">ENTREPRISE</span>
                  </th>
                </tr>
              </thead>
              <tbody>
                {comparisonFeatures.map((feature, i) => (
                  <tr key={i} className={`border-t border-white/5 ${feature.name.includes('Agent IA') ? 'bg-[#E10600]/5' : ''}`}>
                    <td className="p-5 text-xs font-bold uppercase tracking-wider text-slate-400">{feature.name}</td>
                    <td className="p-5 text-center">{renderCellValue(feature.access)}</td>
                    <td className="p-5 text-center">{renderCellValue(feature.terra)}</td>
                    <td className="p-5 text-center">{renderCellValue(feature.mars)}</td>
                    <td className="p-5 text-center bg-white/[0.02]">{renderCellValue(feature.krypton)}</td>
                    <td className="p-5 text-center">{renderCellValue(feature.galaxy)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-5 gap-px mt-12 bg-white/10 overflow-hidden rounded-sm">
            {interpretations.map(item => (
              <div key={item.name} className="p-8 bg-[#141419] text-center">
                <p className="text-xs font-black uppercase tracking-widest mb-2">{item.name}</p>
                <p className="text-xs text-slate-500 italic">{item.desc}</p>
              </div>
            ))}
          </div>

          <div className="mt-32 p-16 bg-[#1A1A1F] border border-white/10 rounded-sm flex flex-col lg:flex-row items-center justify-between gap-12 text-center lg:text-left">
             <div className="space-y-4">
               <h3 className="text-3xl font-black uppercase tracking-tighter">Vous hésitez ?</h3>
               <p className="text-slate-400 font-light italic text-lg max-w-2xl">Commencez avec ACCESS et évoluez à tout moment vers l’intelligence artificielle.</p>
             </div>
             <div className="flex flex-col sm:flex-row gap-4">
                <button onClick={() => onOpenFiko('ACCESS')} className="px-8 py-5 bg-purple-600 text-white text-[9px] font-black uppercase tracking-[0.3em] hover:bg-purple-700 transition-colors">Démarrer avec ACCESS</button>
                <button onClick={() => onOpenFiko()} className="px-8 py-5 bg-white/5 border border-white/10 text-white text-[9px] font-black uppercase tracking-[0.3em] hover:bg-white/10 transition-colors">Parler à un conseiller</button>
                <button onClick={() => onNavigate(Page.AGENTS)} className="px-8 py-5 text-slate-500 text-[9px] font-black uppercase tracking-[0.3em] hover:text-white transition-colors">Voir les solutions IA</button>
             </div>
          </div>

        </div>

      </div>
    </div>
  );
};

export default PricingPage;

import React, { useState, useRef, useEffect } from "react";
import { motion } from "framer-motion";
import { ArrowRight, CheckCircle2 } from 'lucide-react';
import { useCosmic } from "../contexts/CosmicContext";

interface GalacticCardProps {
    id: string;
    title: string;
    story: string;
    price: string;
    subtitle: string;
    features: string[];
    cta: string;
    color: string;
    onClick: () => void;
}

export default function GalacticCard({ id, title, story, price, subtitle, features, cta, color, onClick }: GalacticCardProps) {
  const [isFlipped, setIsFlipped] = useState(false);
  const [rotate, setRotate] = useState({ x: 0, y: 0 });
  const [light, setLight] = useState({ x: 50, y: 50, opacity: 0 });
  const cardRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const { setActiveCardId } = useCosmic();

  const [isTouchDevice, setIsTouchDevice] = useState(false);
  useEffect(() => {
    setIsTouchDevice('ontouchstart' in window || navigator.maxTouchPoints > 0);
  }, []);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current || isTouchDevice) return;
    const rect = cardRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const rotateY = ((x / rect.width) - 0.5) * 20;
    const rotateX = ((y / rect.height) - 0.5) * -20;

    setRotate({ x: rotateX, y: rotateY });

    const lightX = (x / rect.width) * 100;
    const lightY = (y / rect.height) * 100;
    setLight({ x: lightX, y: lightY, opacity: 1 });
  }

  const handleEnter = () => {
    if(isTouchDevice) return;
    setActiveCardId(id);
    setIsFlipped(true);
    if (audioRef.current) {
      audioRef.current.volume = 0.1;
      audioRef.current.play().catch(e => {});
    }
    setLight(prev => ({ ...prev, opacity: 1 }));
  }

  const handleLeave = () => {
    if(isTouchDevice) return;
    setActiveCardId(null);
    setIsFlipped(false);
    setRotate({ x: 0, y: 0 });
    setLight(prev => ({ ...prev, opacity: 0 }));
  }

  const handleClick = () => {
    if(isTouchDevice) {
        const nextFlipped = !isFlipped;
        setIsFlipped(nextFlipped);
        setActiveCardId(nextFlipped ? id : null);
        if(nextFlipped && audioRef.current) {
            audioRef.current.volume = 0.1;
            audioRef.current.play().catch(e => {});
        }
    }
  }

  return (
    <div
      ref={cardRef}
      className="relative w-full h-full perspective"
      onMouseMove={handleMouseMove}
      onMouseEnter={handleEnter}
      onMouseLeave={handleLeave}
      onClick={handleClick}
    >
      <audio ref={audioRef} src="./sounds/galactic-open.mp3" preload="auto" />

      <motion.div
        className="relative w-full h-full"
        animate={{
          rotateY: isFlipped ? 180 + rotate.y : rotate.y,
          rotateX: rotate.x
        }}
        transition={{ type: "spring", stiffness: 200, damping: 30 }}
        style={{ transformStyle: "preserve-3d" }}
      >
        {/* FACE AVANT */}
        <div className="absolute w-full h-full rounded-sm p-8 shadow-2xl backface-hidden flex flex-col justify-between overflow-hidden bg-gradient-to-br from-slate-900 via-black to-slate-900 text-white border-t-4" style={{ borderColor: color }}>
          <div
            className="absolute inset-0 pointer-events-none transition-opacity duration-500"
            style={{
              background: `radial-gradient(circle at ${light.x}% ${light.y}%, ${color}33, transparent 60%)`,
              opacity: light.opacity
            }}
          />
          <div>
            <h2 className="text-2xl font-black mb-4 tracking-tighter uppercase">{title}</h2>
            <p className="text-base opacity-80 leading-relaxed font-light italic line-clamp-6">
              {story}
            </p>
          </div>
          <div className="text-[10px] font-black uppercase tracking-[0.2em] opacity-40 mt-4 animate-pulse">
            {isTouchDevice ? 'Touchez pour activer →' : 'Survolez pour activer →'}
          </div>
        </div>

        {/* FACE ARRIÈRE */}
        <div
          className="absolute w-full h-full rounded-sm p-6 shadow-2xl backface-hidden flex flex-col justify-between bg-black text-white border-t-4"
          style={{ transform: "rotateY(180deg)", borderColor: color }}
        >
          <div className="overflow-hidden flex flex-col flex-grow">
            <h3 className="text-sm font-black uppercase tracking-tighter pt-2 opacity-60">{title}</h3>
            <p className="text-2xl font-black tracking-tighter text-white mt-2">{price}</p>
            <p className="text-[9px] font-bold uppercase tracking-widest text-slate-500 line-clamp-1">{subtitle}</p>
            <ul className="text-sm space-y-3 mt-4 pt-4 border-t border-white/10 overflow-y-auto flex-grow custom-scrollbar pr-2">
              {features.map((f, i) => (
                <li key={i} className="flex items-center gap-3 text-[10px] text-slate-400">
                    <CheckCircle2 size={12} className="text-emerald-500 flex-shrink-0" />
                    <span className="font-bold uppercase tracking-widest">{f}</span>
                </li>
              ))}
            </ul>
          </div>
          <button 
            onClick={(e) => { e.stopPropagation(); onClick(); }}
            className="mt-4 w-full py-4 text-white font-black text-[9px] uppercase tracking-[0.4em] transition-all flex items-center justify-center gap-4 group/btn"
            style={{ backgroundColor: color }}
           >
            {cta}
            <ArrowRight size={14} className="group-hover/btn:translate-x-2 transition-transform" />
          </button>
        </div>
      </motion.div>
    </div>
  );
}
